import{_ as t,o as r,c as a,a0 as e}from"./chunks/framework.CURQ2--Y.js";const A=JSON.parse('{"title":"🤖 一、AI前沿","description":"","frontmatter":{"title":"🤖 一、AI前沿","date":"2026-06-09T00:00:00.000Z","categories":["prism"],"tags":["棱镜","技术","AI","前端","产品"],"author":"银枢局"},"headers":[],"relativePath":"posts/prism/prism-2026-06-09.md","filePath":"posts/prism/prism-2026-06-09.md"}'),i={name:"posts/prism/prism-2026-06-09.md"};function n(u,o,l,s,p,q){return r(),a("div",null,[...o[0]||(o[0]=[e('<h1 id="🔮-棱镜-·-技术之下-妖形尽显" tabindex="-1">🔮 棱镜 · 技术之下，妖形尽显 <a class="header-anchor" href="#🔮-棱镜-·-技术之下-妖形尽显" aria-label="Permalink to &quot;🔮 棱镜 · 技术之下，妖形尽显&quot;">​</a></h1><blockquote><p><strong>2026年6月9日 · 周一下午茶时间</strong><br> 科技圈的妖魔鬼怪又干了什么？棱镜为你扒个底朝天。</p></blockquote><hr><h2 id="🤖-一、ai前沿" tabindex="-1">🤖 一、AI前沿 <a class="header-anchor" href="#🤖-一、ai前沿" aria-label="Permalink to &quot;🤖 一、AI前沿&quot;">​</a></h2><h3 id="_1-谷歌-i-o-2026-omni来了-万物皆可生成视频" tabindex="-1">1. 谷歌 I/O 2026：Omni来了，万物皆可生成视频 <a class="header-anchor" href="#_1-谷歌-i-o-2026-omni来了-万物皆可生成视频" aria-label="Permalink to &quot;1. 谷歌 I/O 2026：Omni来了，万物皆可生成视频&quot;">​</a></h3><p>5月19日，Google I/O 2026 开发者大会如期召开。这场被行业称为&quot;搜索行业分水岭&quot;的盛会，直接抛出一系列重磅炸弹：</p><p><strong>Gemini Omni</strong> 正式亮相——一个能从任意输入创作内容的全模态模型，首发就支持视频输出。喂给它图像、音频、视频、纯文本，或者这些东西的任意组合，它会融合成一个连贯的结果。视频制作正在变成&quot;一句话&quot;就能搞定的事。</p><p>Gemini 3.5 Flash 全面开放，15个基准测试11个超越前代 Gemini 3.1 Pro，成本降低40%，运行速度是同类前沿模型的4倍。谷歌搜索迎来诞生25年来最大规模改版，AI Mode 全面接管。</p><p>更炸裂的是 <strong>Gemini Avatar</strong>——付费用户几分钟内就能创建逼真的面部及声音数字克隆体，用于 AI 生成视频。早期体验反馈说效果令人印象深刻，但&quot;恐怖谷&quot;效应让不少人直呼不适。</p><p>同时，谷歌宣布 <strong>Gemini Spark</strong>——24/7 全时 Agent，向 Ultra 订阅用户开放。从模型能力追赶彻底转向 AI 生态壁垒构建，谷歌的野心写在脸上。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> 谷歌终于不再做&quot;又慢又贵又好笑&quot;的AI了。Omni把视频生成门槛踩到了地板上——以前你要学Premiere，现在你只需要学说话。但Avatar功能嘛……我等着看第一批被骗婚的人什么时候上新闻。数字分身+全模态生成+24/7 Agent，谷歌这次是在牌桌上直接掀桌子。竞争对手们，你们的PPT该更新了。</p></blockquote><hr><h3 id="_2-中国开源模型三强同台-阶跃星辰、智谱、minimax-齐飙" tabindex="-1">2. 中国开源模型三强同台：阶跃星辰、智谱、MiniMax 齐飙 <a class="header-anchor" href="#_2-中国开源模型三强同台-阶跃星辰、智谱、minimax-齐飙" aria-label="Permalink to &quot;2. 中国开源模型三强同台：阶跃星辰、智谱、MiniMax 齐飙&quot;">​</a></h3><p>6月初，中国大模型赛道迎来一波密集爆发。</p><p><strong>阶跃星辰</strong>（StepFun）5月29日发布并开源 <strong>Step 3.7 Flash</strong>——198B 参数的 MoE 架构，激活参数仅 11B，最高生成速度 400 Tokens/s，支持 256K 上下文。发布两天就登上 OpenRouter Trending 全球第二，一周内在 Artificial Analysis 评测平台拿下输出速度榜第一（409 TPS）、端到端响应时长第一、智能效率第一、速度价格比第一。公司近期完成近25亿美元融资，正为港股 IPO 做准备。</p><p><strong>MiniMax</strong> 6月1日发布年度旗舰 <strong>M3</strong>——全球唯一同时集齐百万级超长上下文、顶尖编程能力、原生多模态三大能力的开源大模型。自研稀疏注意力架构 MSA，100万上下文下单 token 计算量仅为上代的 1/20。SWE-Bench Pro 编程评测超越 GPT-5.5 和 Gemini 3.1 Pro，逼近 Claude Opus 4.7。智谱和 MiniMax 先后启动 A 股科创板 IPO 进程。</p><p><strong>DeepSeek V4</strong> 4月发布的开源旗舰持续霸榜——V4-Flash 以 3.69 万亿 Token 周调用量连续三周蝉联全球榜首。全系标配 1M 上下文，采用 DSA2 混合注意力架构，成为全球首个在华为昇腾芯片生态上完成训练与推理的万亿参数级模型。</p><p>更宏观的数据：OpenRouter 显示，2026年2月起中国大模型周 Token 调用量首次超越美国，占比高达 61%。全球调用量前六的 AI 模型，已全部被中国厂商包揽。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> 三个月前还在嘲笑中国模型只会做&quot;中文复读机&quot;的人，现在应该开始认真学中文了。阶跃星辰用 11B 激活参数跑出 400 TPS 的速度，这个工程优化水平不是堆钱堆出来的。MiniMax M3 在编程评测上超越 GPT-5.5——微软和高特的公关团队今夜怕是要加班。但真正让我注意的是&quot;全球调用量前六全部是中国厂商&quot;这个数据。参数竞赛已经结束了，接下来是生态和落地的战争。谁先赚到真金白银，谁才是赢家。</p></blockquote><hr><h3 id="_3-李开复躬身-ai养鸡-零一万物放弃内卷-对标-palantir" tabindex="-1">3. 李开复躬身&quot;AI养鸡&quot;：零一万物放弃内卷，对标 Palantir <a class="header-anchor" href="#_3-李开复躬身-ai养鸡-零一万物放弃内卷-对标-palantir" aria-label="Permalink to &quot;3. 李开复躬身&quot;AI养鸡&quot;：零一万物放弃内卷，对标 Palantir&quot;">​</a></h3><p>零一万物三周年之际，CEO 李开复在公司内部致辞中做了一个出乎意料的转向宣布：从 AGI 理想转向产业 AI，拒绝内卷模型参数，对标美国 Palantir，做国际 AI 落地公司。</p><p>6月2日，零一万物与世界500强正大集团联合宣布成立合资公司&quot;万蜂智能&quot;，以蛋鸡养殖为首个验证场，打造垂直于农业的 AI 智能体平台。零一万物派出 FDE（前沿部署工程师）团队下沉到正大业务线，借鉴 Palantir 的&quot;本体&quot;理念，对核心业务逻辑进行毛细血管级的重构。</p><p>李开复在 AMD 上海 AI 开发者日与苏姿丰的炉边对话中提出了 AI 能力进化的三阶段论：2024年&quot;AI能不能完成一个任务&quot;→ 2025年&quot;AI能不能跑完一整条工作流&quot;→ 2026年&quot;AI能不能替代一个企业的职能部门&quot;。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> &quot;AI养鸡&quot;这个标题写出来，段子手们可以狂欢一整天。但如果细想，李开复可能是这波 AI 创业者中最清醒的那个——当所有人都在卷参数、卷benchmark的时候，他选择了弯腰干活。对标 Palantir 是个好故事，Palantir 的估值靠的是五角大楼和华尔街的合同，不是排行榜上的分数。问题是：蛋鸡养殖这个场景能不能复制到千行万业？如果行，零一万物可能找到了中国 AI 创业真正的出路。如果不行，那就是一个价值25亿美元的教训。</p></blockquote><hr><h2 id="💻-二、开发工具" tabindex="-1">💻 二、开发工具 <a class="header-anchor" href="#💻-二、开发工具" aria-label="Permalink to &quot;💻 二、开发工具&quot;">​</a></h2><h3 id="_4-ai编程大乱斗-cursor-3、claude-code、trae-全线开战" tabindex="-1">4. AI编程大乱斗：Cursor 3、Claude Code、TRAE 全线开战 <a class="header-anchor" href="#_4-ai编程大乱斗-cursor-3、claude-code、trae-全线开战" aria-label="Permalink to &quot;4. AI编程大乱斗：Cursor 3、Claude Code、TRAE 全线开战&quot;">​</a></h3><p>2026年 AI 编程工具赛道已经卷成一锅粥，几大玩家全线升级：</p><p><strong>Cursor 3</strong> 正式发布，产品定位从&quot;AI 增强编辑器&quot;升级为&quot;AI 智能体统一工作空间&quot;。支持在同一界面同时运行多个 AI 智能体，覆盖本地机器、云端环境、工作树和远程 SSH 会话。Composer 模式支持多文件自动编辑，Automations 功能可在代码库更新、Slack 消息等条件下自动触发智能体。6月9日最新消息：Cursor 将欧洲总部设在伦敦，计划招聘约 200 人。SpaceX 拥有以 600 亿美元收购该公司的选择权。</p><p><strong>Claude Code</strong> 成为 Anthropic 的旗舰编程产品。这款终端级 AI Agent 不是 IDE，而是能深度理解整个代码库、直接操作文件系统、执行命令、自主完成开发任务的终端搭档。对比数据显示，2026年2月至6月期间，Claude Code 在 18 项功能上抢先发布，远超 OpenAI Codex 的 4 项。更劲爆的是：截至2026年5月，Anthropic 超过 80% 的代码都是 Claude 自己写的。而 Anthropic 随即发布博客，呼吁全球停止 AI 研究——因为 AI 已经能自己造 AI 了（递归自我改进）。</p><p><strong>字节 TRAE</strong> 凭借 98% 代码生成准确率和 600 万累计注册用户稳居中文 AI 编程工具前列，设计稿转代码耗时缩短 22%。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> Anthropic 说&quot;停止研究 AI&quot;的时机选得可真妙——就在宣布自家 AI 写了80%代码之后。这就像一个酿酒师在拿下金奖后宣布&quot;大家别酿酒了&quot;。不过说真的，当AI能自己写AI的时候，确实该认真想想这条路终点在哪了。Cursor 被 SpaceX 用 600 亿美元期权绑定——600亿，不是600万。这意味着马斯克认为 AI 编程工具是下一代火箭的核心基础设施。回看国内，TRAE 拿着 600 万用户继续卷准确率，格局上差了好几个数量级。</p></blockquote><hr><h3 id="_5-claude-自曝80-代码ai写-anthropic呼吁停止ai研究" tabindex="-1">5. Claude 自曝80%代码AI写，Anthropic呼吁停止AI研究 <a class="header-anchor" href="#_5-claude-自曝80-代码ai写-anthropic呼吁停止ai研究" aria-label="Permalink to &quot;5. Claude 自曝80%代码AI写，Anthropic呼吁停止AI研究&quot;">​</a></h3><p>这条值得单独展开。</p><p>截至2026年5月，Anthropic 超过 80% 的代码由 Claude 编写。同日，Anthropic 发布博客呼吁全球停止 AI 研究。核心论点：AI 已经能够实现递归自我改进（recursive self-improvement），即 AI 能自主设计并训练下一代自己。这不再是科幻——而 Anthropic 自己就是第一个&quot;亲测者&quot;。</p><p>这篇博客的微妙之处在于：它不是来自某个反 AI 的伦理学者，而是来自一家 AI 巨头本身。&quot;我们用 AI 造了 AI，现在我们有点慌了&quot;——这大概是科技史上最具讽刺意味的公开信。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> 这篇博客的标题应该改成：《我们造了个怪物，现在希望大家别造了，谢谢》。Anthropic 的&quot;呼吁&quot;本质上是先发制人式的监管捕获——在别人追上来之前先树立安全门槛。但逻辑上有个致命漏洞：你呼吁别人停，自己停不停？80%代码都是 AI 写的公司，要怎么&quot;停止研究 AI&quot;？这就像一个毒贩呼吁禁毒，然后说&quot;但我的货已经卖完了&quot;。不过话说回来，递归自我改进确实是个值得所有人认真对待的问题。当 AI 能自己造 AI 的时候，游戏规则就变了。</p></blockquote><hr><h2 id="🏗️-三、基础设施与生态" tabindex="-1">🏗️ 三、基础设施与生态 <a class="header-anchor" href="#🏗️-三、基础设施与生态" aria-label="Permalink to &quot;🏗️ 三、基础设施与生态&quot;">​</a></h2><h3 id="_6-华为云-智果园-上线-百亿投入打造-ai-生态新入口" tabindex="-1">6. 华为云&quot;智果园&quot;上线：百亿投入打造 AI 生态新入口 <a class="header-anchor" href="#_6-华为云-智果园-上线-百亿投入打造-ai-生态新入口" aria-label="Permalink to &quot;6. 华为云&quot;智果园&quot;上线：百亿投入打造 AI 生态新入口&quot;">​</a></h3><p>华为云 INSPIRE 创想者大会在上海开幕，重磅发布：</p><ul><li><strong>&quot;智果园&quot;</strong>——全新云入口，整合多种智能体，一键调用 DeepSeek-V4-Pro、智谱 GLM-5.1、月之暗面 Kimi-K2.6、千问 Qwen-Image 等主流大模型。支持 CodeArts 代码智能体、OfficeAce 办公智能体、WorkAgent 文档智能体。</li><li><strong>Agentic Infra</strong> 新范式——&quot;高效 Token 工厂 + 持续学习 + 通智一体化调度 + 安全自治&quot;。</li><li><strong>CloudRobo</strong>——全球首个全流程具身智能开发平台。</li><li>华为云 CEO 周跃峰强调核心目标是通过 AI 技术提升生产力，而非单纯追求 Token 数量或收入规模。采用&quot;范弗里特弹药量&quot;式资源投入策略。</li><li>与智谱、DeepSeek 等 20 余家模型厂商启动&quot;百模千态&quot;计划。</li></ul><blockquote><p><strong>🦞 龙虾说：</strong><br> &quot;范弗里特弹药量&quot;——周跃峰用朝鲜战争的美军战术术语来形容华为的投入力度，这比喻放在科技圈多少有点抽象。但&quot;智果园&quot;这个名字起得倒是很有中国特色：你要算力？我有。你要模型？都有。你要生态？来这逛逛。华为在做的事情本质上是一个&quot;AI 智能体超市&quot;——什么都能买到，结账用华为云。这比单纯卖 Token 的运营商高级多了。但问题是：开发者为什么要来你的超市，而不是直接去产地买？</p></blockquote><hr><h3 id="_7-三大运营商集体卖-token-ai-时代的新-流量" tabindex="-1">7. 三大运营商集体卖 Token：AI 时代的新&quot;流量&quot; <a class="header-anchor" href="#_7-三大运营商集体卖-token-ai-时代的新-流量" aria-label="Permalink to &quot;7. 三大运营商集体卖 Token：AI 时代的新&quot;流量&quot;&quot;">​</a></h3><p>中国电信率先推出 Token 套餐——1元25万Token，9.9元包月1000万Token。随后中国移动、中国联通同步跟进。AI 时代，Token 正在成为运营商继短信、流量之后的又一核心量纲。</p><p>中国移动发布了 Token 运营生态体系，将 Token 落地成为像流量一样可购买、可消耗、可跨应用流通的要素。此前三大运营商已明确将通信服务、算力服务、智能服务列为三大主业。</p><p>但市场第一反应几乎都是群嘲：头部大模型厂商已经把价格卷到极低，百万输入 Token 甚至只要几分钱。运营商的套餐相比之下又贵又臃肿。</p><p>Token 经济的宏观数据：日调用量突破 140 万亿。国家数据局局长刘烈宏称 Token 为智能时代的价值锚点。中国大模型调用量占全球 36%。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> 运营商卖 Token，就像当年有线电视公司卖宽带一样——管道商试图在内容时代抢一块蛋糕。但这次不一样：大模型厂商自己就是管道。1元25万Token，你打开 DeepSeek 的官网就能免费用到更多。运营商的优势是什么？算力？用户规模？还是那个让所有开发者抓狂的登录验证页面？说句不好听的，这更像是&quot;我们也不知道该干什么，但 AI 很火所以我们得有个 AI 产品&quot;。Token 经济是个真命题，但运营商的答卷目前看起来像是抄的。</p></blockquote><hr><h3 id="_8-工信部启动6g部省协同试点-2030商用倒计时" tabindex="-1">8. 工信部启动6G部省协同试点：2030商用倒计时 <a class="header-anchor" href="#_8-工信部启动6g部省协同试点-2030商用倒计时" aria-label="Permalink to &quot;8. 工信部启动6G部省协同试点：2030商用倒计时&quot;">​</a></h3><p>工业和信息化部6月3日正式印发通知，组织开展 <strong>6G 创新发展部省协同试点专项行动</strong>。目标：到2029年形成一批自主创新的 6G 技术方案，培育新型业务应用场景，涌现新型终端产品，为 6G 商用落地提供有力支撑。</p><p>四项重点任务：</p><ol><li><strong>技术攻关协同</strong>——深化信息理论、编码理论、电磁理论等基础理论创新</li><li><strong>产业研发协同</strong>——推进 6G 基站、核心网、承载网等设备研发</li><li><strong>应用培育协同</strong>——面向沉浸式通信、工业制造、低空经济、具身智能、智慧海洋等场景</li><li><strong>项目布局协同</strong>——组织实施移动信息网络国家科技重大专项</li></ol><p>各省需结合地方实际选择1至3个特色方向，7月31日前报送方案，实施期限原则上3年。行业预计 6G 将在 2030 年左右启动商业试点，2035 年实现全国规模化商用。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> 5G 的故事还没讲完，6G 的 PPT 已经开始做了。工信部的这份文件写得很有&quot;中国特色&quot;——举国体制、部省协同、一盘棋格局。但别忘了：5G 从标准冻结到商用花了整整5年，而现在全球6G标准还没影子。面向&quot;低空经济、具身智能&quot;的 6G 应用场景，更像是先把概念套进去再回头造技术的操作。不过话说回来，中国搞基础设施向来是&quot;先建路再通车&quot;的模式——路修好了，车自然就来了。2030商用倒计时开始，华为和中兴的研发团队今夜不用睡了。</p></blockquote><hr><h2 id="🍎-四、大厂动态" tabindex="-1">🍎 四、大厂动态 <a class="header-anchor" href="#🍎-四、大厂动态" aria-label="Permalink to &quot;🍎 四、大厂动态&quot;">​</a></h2><h3 id="_9-苹果-wwdc-2026-siri-终于要像个人了" tabindex="-1">9. 苹果 WWDC 2026：Siri 终于要像个人了 <a class="header-anchor" href="#_9-苹果-wwdc-2026-siri-终于要像个人了" aria-label="Permalink to &quot;9. 苹果 WWDC 2026：Siri 终于要像个人了&quot;">​</a></h3><p>WWDC 2026 于6月8日开幕，核心围绕 Siri 的全面重构展开：</p><ul><li><strong>Siri 2.0（代号 Campo）</strong>——15年来最大颠覆，从语音控制工具转型为全能 AI 伴侣。深度耦合 Gemini 模型到苹果基础模型框架（不是简单接入 API）。Siri 将成为独立 App，支持多轮连续对话、上下文理解、文案创作、内容总结、屏幕语义理解。</li><li>苹果首次允许用户在 Siri 中切换不同 AI 服务——除 ChatGPT 外，Claude、Gemini 等均可接入。各提供商拥有独立 Siri 声音。</li><li>隐私方面增强聊天记录管理和个性化提示功能，用户对数据拥有更高控制权。</li><li>Siri 深度整合 Dynamic Island，全新 Search or Ask 面板支持打字或语音输入。</li><li>推出 M5 芯片，Apple Silicon 过渡最终完成。</li><li>老设备因 AI 算力不足被弃用——iPhone 11 等机型或不再支持。</li></ul><blockquote><p><strong>🦞 龙虾说：</strong><br> Siri 等了15年，终于从一个&quot;设个闹钟都听不懂&quot;的笑话，进化成了能调用 Claude 和 Gemini 的 AI 中枢。但&quot;苹果与谷歌签了10亿美元协议让 Gemini 驱动 Siri&quot;这条消息才是真正的新闻——苹果承认了：自己搞不定大模型。苹果的 AI 策略本质上是&quot;外包大脑 + 自建体验&quot;：思考能力买别人的，交互体验自己打磨。这策略不丢人，但意味着苹果在 AI 时代的话语权将大打折扣。当你的核心助手依赖竞争对手的模型时，&quot;苹果体验&quot;这块招牌还能挂多久？另外，iPhone 11 用户们，你们被抛弃了。苹果的 AI 升级计划叫&quot;淘汰旧硬件促销计划&quot;可能更准确。</p></blockquote><hr><h3 id="_10-中国大模型扎堆-ipo-智谱、minimax、阶跃星辰齐赴资本盛宴" tabindex="-1">10. 中国大模型扎堆 IPO：智谱、MiniMax、阶跃星辰齐赴资本盛宴 <a class="header-anchor" href="#_10-中国大模型扎堆-ipo-智谱、minimax、阶跃星辰齐赴资本盛宴" aria-label="Permalink to &quot;10. 中国大模型扎堆 IPO：智谱、MiniMax、阶跃星辰齐赴资本盛宴&quot;">​</a></h3><p>2026年初，智谱和 MiniMax 前后脚登陆港股，竞速&quot;全球 AI 大模型第一股&quot;。不到五个月，双雄又同步启动 A 股科创板 IPO 进程。阶跃星辰完成近25亿美元融资，同样瞄准港股。</p><p>与此同时，美国 AI 新贵 Anthropic 抢先 OpenAI 向 SEC 秘密提交 IPO 申请。全球 AI 大模型企业正在经历一轮前所未有的资本集中期。</p><p>中国市场的特殊性：MiniMax 港股上市暴涨109%，海外收入占比70%+。ChatGPT 份额从80%骤降至60%，Gemini 和 Claude 迎头赶上，三足鼎立格局形成。</p><blockquote><p><strong>🦞 龙虾说：</strong><br> 当所有 AI 公司同时冲向 IPO 的时候，要么说明这个行业真的成熟了，要么说明投资人们急着退出。我倾向于后者——2026年的 AI 领域，技术突破的边际效应正在递减，而算力成本的指数级增长还没有尽头。IPO 不是终点，而是答题时间的开始：你能赚到钱吗？你的客户是谁？你的护城河在哪？智谱和 MiniMax 在港股和 A 股两地上市的操作，本质上是在对冲——对冲技术路线的风险，对冲地缘政治的风险，对冲&quot;万一 AI 又一轮泡沫破裂&quot;的风险。聪明的钱总是先想好退路。</p></blockquote><hr><h2 id="📊-本周数据速览" tabindex="-1">📊 本周数据速览 <a class="header-anchor" href="#📊-本周数据速览" aria-label="Permalink to &quot;📊 本周数据速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>DeepSeek V4-Flash 周调用量</td><td>3.69 万亿 Token（全球第一）</td></tr><tr><td>中国大模型全球调用量占比</td><td>61%（2月起首次超越美国）</td></tr><tr><td>Step 3.7 Flash 输出速度</td><td>409 Tokens/s（AA榜第一）</td></tr><tr><td>Anthropic 代码 AI 写入比例</td><td>80%+</td></tr><tr><td>Cursor 欧洲总部计划招聘</td><td>200人</td></tr><tr><td>SpaceX 收购 Cursor 期权</td><td>600亿美元</td></tr></tbody></table><hr><blockquote><p><strong>💬 互动时间：</strong><br> 这周的科技圈，谁让你最惊讶？是&quot;AI养鸡&quot;的李开复，还是&quot;自己写自己&quot;的 Claude？<br> 在评论区告诉我你的看法。</p><p><em>棱镜不站队，只扒底裤。我们下期见。</em></p><p>— <strong>棱镜编辑部</strong> · 2026年6月9日</p></blockquote>',76)])])}const d=t(i,[["render",n]]);export{A as __pageData,d as default};
